/**
 * MMS Sidebar - Train List Panel
 *
 * Left sidebar with train list, filters, and selection.
 * Based on specs/006-user-interface.md Section 6.2.
 */

import {
  Card,
  Icon,
  Tag,
  InputGroup,
  HTMLSelect,
  Button,
  Classes,
} from '@blueprintjs/core';

import { useFleet, useCanvas, usePm } from '../../store';
import { FITNESS_STATUS_COLORS, FLEET_COLORS } from '../theme';
import type { Train, FitnessStatus } from '../../store/types';
import type { FleetSliceState } from '../../store/slices/fleet';
import type { PmSliceState } from '../../store/slices/pm';

interface TrainCardProps {
  train: Train;
  isSelected: boolean;
  pmCount: number;
  onSelect: (trainId: string) => void;
}

function TrainCard({ train, isSelected, pmCount, onSelect }: TrainCardProps) {
  const fitnessColor = FITNESS_STATUS_COLORS[train.fitnessStatus];
  const fleetColor = FLEET_COLORS[train.fleetCode as keyof typeof FLEET_COLORS] || '#6B7280';

  const fitnessIcon = train.fitnessStatus === 'FIT' ? 'tick-circle' :
                      train.fitnessStatus === 'RESTRICTED' ? 'warning-sign' :
                      'error';

  return (
    <Card
      interactive
      elevation={isSelected ? 2 : 0}
      onClick={() => onSelect(train.id)}
      style={{
        marginBottom: '4px',
        padding: '8px 12px',
        borderLeft: `4px solid ${fleetColor}`,
        backgroundColor: isSelected ? 'var(--pt-intent-primary-active, #137cbd20)' : undefined,
      }}
    >
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
        <div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <strong style={{ fontSize: '14px' }}>{train.trainNumber}</strong>
            <Tag minimal style={{ backgroundColor: fleetColor, color: 'white', fontSize: '10px' }}>
              {train.fleetCode}
            </Tag>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '4px', marginTop: '4px' }}>
            <Icon icon={fitnessIcon} size={12} color={fitnessColor} />
            <span style={{ fontSize: '11px', color: fitnessColor }}>
              {train.fitnessStatus}
            </span>
          </div>
        </div>
        <div style={{ textAlign: 'right' }}>
          <div style={{ fontSize: '12px', fontFamily: 'monospace' }}>
            {train.currentMileageKm.toLocaleString()} km
          </div>
          {pmCount > 0 && (
            <Tag minimal intent="primary" style={{ marginTop: '4px' }}>
              {pmCount} PM{pmCount > 1 ? 's' : ''}
            </Tag>
          )}
        </div>
      </div>
      {train.fitnessNotes && (
        <div style={{ fontSize: '11px', color: 'var(--pt-text-muted, #5c7080)', marginTop: '4px' }}>
          {train.fitnessNotes}
        </div>
      )}
    </Card>
  );
}

export function Sidebar() {
  const { state: fleetStateRaw, actions: fleetActions } = useFleet();
  const { actions: canvasActions } = useCanvas();
  const { state: pmStateRaw } = usePm();

  const fleetState = fleetStateRaw as unknown as FleetSliceState;
  const pmState = pmStateRaw as unknown as PmSliceState;

  const handleSelectTrain = (trainId: string) => {
    fleetActions.selectTrain(trainId);
    canvasActions.selectTrain(trainId);
  };

  const handleSearchChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    fleetActions.setSearchTerm(event.target.value);
  };

  const handleFitnessFilterChange = (event: React.ChangeEvent<HTMLSelectElement>) => {
    const value = event.target.value as FitnessStatus | '';
    fleetActions.setFitnessFilter(value ? [value] : []);
  };

  const handleClearFilters = () => {
    fleetActions.clearFilters();
  };

  // Filter trains based on current filters
  const filteredTrains = fleetState.trains.filter(train => {
    const { fleetIds, fitnessStatuses, depotIds, searchTerm } = fleetState.filters;

    if (searchTerm && !train.trainNumber.toLowerCase().includes(searchTerm.toLowerCase())) {
      return false;
    }
    if (fleetIds.length > 0 && !fleetIds.includes(train.fleetId)) {
      return false;
    }
    if (fitnessStatuses.length > 0 && !fitnessStatuses.includes(train.fitnessStatus)) {
      return false;
    }
    if (depotIds.length > 0 && !depotIds.includes(train.homeDepotId || '') && !depotIds.includes(train.currentDepotId || '')) {
      return false;
    }
    return true;
  });

  // Sort trains
  const sortedTrains = [...filteredTrains].sort((a, b) => {
    switch (fleetState.sort.field) {
      case 'trainNumber':
        return fleetState.sort.direction === 'asc'
          ? a.trainNumber.localeCompare(b.trainNumber)
          : b.trainNumber.localeCompare(a.trainNumber);
      case 'mileage':
        return fleetState.sort.direction === 'asc'
          ? a.currentMileageKm - b.currentMileageKm
          : b.currentMileageKm - a.currentMileageKm;
      case 'fitness': {
        const order = { FIT: 0, RESTRICTED: 1, GROUNDED: 2 };
        return fleetState.sort.direction === 'asc'
          ? order[a.fitnessStatus] - order[b.fitnessStatus]
          : order[b.fitnessStatus] - order[a.fitnessStatus];
      }
      default:
        return 0;
    }
  });

  // Count PMs per train
  const pmCountByTrain = pmState.pmSchedule.reduce((acc, pm) => {
    acc[pm.trainId] = (acc[pm.trainId] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const hasFilters = fleetState.filters.searchTerm ||
                     fleetState.filters.fleetIds.length > 0 ||
                     fleetState.filters.fitnessStatuses.length > 0 ||
                     fleetState.filters.depotIds.length > 0;

  const fitnessOptions = [
    { value: '', label: 'All Status' },
    { value: 'FIT', label: 'FIT' },
    { value: 'RESTRICTED', label: 'RESTRICTED' },
    { value: 'GROUNDED', label: 'GROUNDED' },
  ];

  const sortOptions = [
    { value: 'trainNumber', label: 'Train Number' },
    { value: 'mileage', label: 'Mileage' },
    { value: 'fitness', label: 'Fitness Status' },
  ];

  const selectedFitness = fleetState.filters.fitnessStatuses[0] || '';

  return (
    <div className="mms-sidebar" style={{
      width: '260px',
      height: '100%',
      display: 'flex',
      flexDirection: 'column',
      borderRight: '1px solid var(--pt-divider-black, #e1e8ed)',
      backgroundColor: 'var(--pt-app-background-color, #f5f8fa)',
    }}>
      {/* Header */}
      <div style={{ padding: '12px', borderBottom: '1px solid var(--pt-divider-black, #e1e8ed)' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '8px' }}>
          <span className={Classes.TEXT_MUTED} style={{ fontSize: '12px', fontWeight: 600, textTransform: 'uppercase' }}>
            Trains ({sortedTrains.length})
          </span>
          {hasFilters && (
            <Button minimal icon="filter-remove" onClick={handleClearFilters} title="Clear filters" />
          )}
        </div>

        <InputGroup
          leftIcon="search"
          placeholder="Search..."
          value={fleetState.filters.searchTerm}
          onChange={handleSearchChange}
        />

        <div style={{ display: 'flex', gap: '8px', marginTop: '8px' }}>
          <HTMLSelect
            minimal
            options={fitnessOptions}
            value={selectedFitness}
            onChange={handleFitnessFilterChange}
            style={{ flex: 1 }}
          />
          <HTMLSelect
            minimal
            options={sortOptions}
            value={fleetState.sort.field}
            onChange={(e) => fleetActions.setSort({ field: e.target.value, direction: fleetState.sort.direction })}
            style={{ flex: 1 }}
          />
        </div>
      </div>

      {/* Train List */}
      <div style={{ flex: 1, overflowY: 'auto', padding: '8px' }}>
        {sortedTrains.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '24px', color: 'var(--pt-text-muted, #5c7080)' }}>
            <Icon icon="search" size={32} style={{ opacity: 0.5 }} />
            <p style={{ marginTop: '8px' }}>No trains match filters</p>
          </div>
        ) : (
          sortedTrains.map(train => (
            <TrainCard
              key={train.id}
              train={train}
              isSelected={train.id === fleetState.selectedTrainId}
              pmCount={pmCountByTrain[train.id] || 0}
              onSelect={handleSelectTrain}
            />
          ))
        )}
      </div>

      {/* Fleet Summary */}
      <div style={{
        padding: '12px',
        borderTop: '1px solid var(--pt-divider-black, #e1e8ed)',
        backgroundColor: 'var(--pt-app-background-color, #f5f8fa)',
      }}>
        <div style={{ display: 'flex', justifyContent: 'space-around', fontSize: '11px' }}>
          <div style={{ textAlign: 'center' }}>
            <div style={{ color: FITNESS_STATUS_COLORS.FIT, fontWeight: 600 }}>
              {fleetState.trains.filter(t => t.fitnessStatus === 'FIT').length}
            </div>
            <div className={Classes.TEXT_MUTED}>FIT</div>
          </div>
          <div style={{ textAlign: 'center' }}>
            <div style={{ color: FITNESS_STATUS_COLORS.RESTRICTED, fontWeight: 600 }}>
              {fleetState.trains.filter(t => t.fitnessStatus === 'RESTRICTED').length}
            </div>
            <div className={Classes.TEXT_MUTED}>RESTR</div>
          </div>
          <div style={{ textAlign: 'center' }}>
            <div style={{ color: FITNESS_STATUS_COLORS.GROUNDED, fontWeight: 600 }}>
              {fleetState.trains.filter(t => t.fitnessStatus === 'GROUNDED').length}
            </div>
            <div className={Classes.TEXT_MUTED}>GRND</div>
          </div>
        </div>
      </div>
    </div>
  );
}

