   247→    // ==========================================================================
   248→
   249→    setError: (
   250→      s,
   251→      payload: { message: string; code?: string; details?: Record<string, unknown> }
   252→    ) => {
   253→      const state = s as UiSliceState;
   254→      state.error = {
   255→        message: payload.message,
   256→        code: payload.code ?? null,
   257→        details: payload.details ?? null,
